#include "persistent_log.h"
#include "crc32.h"
#include <string.h>
static uint32_t hcrc(const log_header_t*h){return crc32_compute((const uint8_t*)h,offsetof(log_header_t,header_crc));}
void persistent_log_init(persistent_log_t*l,uint8_t*m,size_t s){if(l)*l=(persistent_log_t){.media=m,.size=s,.next_sequence=1};}
status_t persistent_log_append(persistent_log_t*l,uint32_t ts,const uint8_t*p,uint16_t n){if(!l||!p||n==0)return STATUS_INVALID_ARGUMENT;size_t total=sizeof(log_header_t)+n;if(total>l->size)return STATUS_NO_SPACE;if(l->write_offset+total>l->size)l->write_offset=0;log_header_t h={.magic=LOG_MAGIC,.sequence=l->next_sequence++,.timestamp_ms=ts,.version=1,.payload_length=n,.payload_crc=crc32_compute(p,n),.commit=0};h.header_crc=hcrc(&h);memcpy(l->media+l->write_offset,&h,sizeof h);memcpy(l->media+l->write_offset+sizeof h,p,n);h.commit=LOG_COMMIT;memcpy(l->media+l->write_offset+offsetof(log_header_t,commit),&h.commit,sizeof h.commit);l->write_offset+=total;return STATUS_OK;}
status_t persistent_log_scan(persistent_log_t*l){if(!l)return STATUS_INVALID_ARGUMENT;size_t off=0;l->recovered_records=0;while(off+sizeof(log_header_t)<=l->size){log_header_t h;memcpy(&h,l->media+off,sizeof h);if(h.magic!=LOG_MAGIC)break;if(h.payload_length==0||off+sizeof h+h.payload_length>l->size||h.commit!=LOG_COMMIT||h.header_crc!=hcrc(&h)){l->crc_failures++;break;}if(crc32_compute(l->media+off+sizeof h,h.payload_length)!=h.payload_crc){l->crc_failures++;break;}l->recovered_records++;if(h.sequence>=l->next_sequence)l->next_sequence=h.sequence+1;off+=sizeof h+h.payload_length;}l->write_offset=off;return STATUS_OK;}
